+// Draw a warm torch glow with flicker effect
+function drawTorchGlow(ctx: CanvasRenderingContext2D, x: number, y: number, baseRadius: number, intensity: number) {
+  // Flicker radius ±2px
+  const flicker = (Math.sin(Date.now() / 150) + Math.sin(Date.now() / 200 + 10)) * 1; // approx ±2
+  const radius = baseRadius + flicker;
+
+  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
+  gradient.addColorStop(0, `rgba(255, 200, 100, ${0.6 * intensity})`); // bright warm core
+  gradient.addColorStop(0.4, `rgba(255, 140, 30, ${0.3 * intensity})`);
+  gradient.addColorStop(1, `rgba(255, 100, 0, 0)`); // fade out
+
+  ctx.fillStyle = gradient;
+  ctx.beginPath();
+  ctx.arc(x, y, radius, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // Original torch drawing code (assumed to be here)
+  // Example torch body (simple orange flame shape)
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.fillStyle = '#ffb84d';
+  ctx.beginPath();
+  ctx.moveTo(0, 0);
+  ctx.bezierCurveTo(4, -8, 8, -4, 0, -16);
+ ctx.bezierCurveTo(-8, -4, -4, -8, 0, 0);
+  ctx.fill();
+  ctx.restore();
+
+  // Draw torch glow behind the torch
+  drawTorchGlow(ctx, x, y - 8, 20, 1);
+}
