+function drawRoomLighting(ctx: CanvasRenderingContext2D, roomWidth: number, roomHeight: number, torches: {x: number, y: number}[]) {
+  // Darken room corners with radial gradient overlay
+  const cornerGradient = ctx.createRadialGradient(0, 0, 0, 0, 0, Math.max(roomWidth, roomHeight) / 2);
+  cornerGradient.addColorStop(0, 'rgba(0,0,0,0)');
+  cornerGradient.addColorStop(1, 'rgba(0,0,0,0.6)');
+
+  // Fill entire room with transparent black to darken corners
+  ctx.save();
+  ctx.fillStyle = cornerGradient;
+  // Draw 4 corner gradients by translating canvas
+  // Top-left corner
+  ctx.translate(0, 0);
+  ctx.fillRect(0, 0, roomWidth / 2, roomHeight / 2);
+  // Top-right corner
+  ctx.translate(roomWidth, 0);
+  ctx.scale(-1, 1);
+  ctx.fillRect(0, 0, roomWidth / 2, roomHeight / 2);
+  ctx.scale(-1, 1);
+  ctx.translate(-roomWidth, 0);
+  // Bottom-left corner
+  ctx.translate(0, roomHeight);
+  ctx.scale(1, -1);
+  ctx.fillRect(0, 0, roomWidth / 2, roomHeight / 2);
+  ctx.scale(1, -1);
+  ctx.translate(0, -roomHeight);
+  // Bottom-right corner
+  ctx.translate(roomWidth, roomHeight);
+  ctx.scale(-1, -1);
+  ctx.fillRect(0, 0, roomWidth / 2, roomHeight / 2);
+  ctx.restore();
+
+  // Draw torches with glow
+  for (const torch of torches) {
+    drawTorch(ctx, torch.x, torch.y);
+  }
+}
